1	export type ProjectStatus = "Draft" | "Active" | "Blocked" | "Archived";
2	export type PhaseStatus = "DraftSpec" | "SpecApproved" | "PRDAttached" | "ReadyForBuild" | "Accepted" | "ReworkRequired" | "Closed";
3	export type FreezeState = "Locked" | "FrozenDownstream" | "EditableDownstream" | "DownstreamRevisionRequired";
4	export type ConversationSystem = "Claude" | "ChatGPT" | "Other";
5	export type ConversationRole = "planning" | "prd" | "architecture" | "review" | "revision";
6	export type ConversationStatus = "active" | "reference" | "archived";
7	export type ScopeType = "project" | "phase";
8	
9	export interface DevProject { id: string; name: string; objective: string; owner: string; status: ProjectStatus; activePhaseId: string | null; roadmapSummary: string; createdAt: string; updatedAt: string; }
10	export interface Phase { id: string; projectId: string; phaseNumber: number; title: string; objective: string; description: string; status: PhaseStatus; prerequisites: string; successCriteria: string; riskNotes: string; freezeState: FreezeState; sortOrder: number; createdAt: string; updatedAt: string; }
11	export interface Spec { id: string; phaseId: string; title: string; sourceRef: string; version: string; author: string; approvalState: string; notes: string; }
12	export interface PRD { id: string; phaseId: string; title: string; sourceRef: string; version: string; approvalState: string; deviationNotes: string; notes: string; }
13	export interface BuildDispatch { id: string; phaseId: string; status: string; buildClass: string; riskLevel: string; targetRepo: string; environment: string; createdAt: string; }
14	export interface BuildOutput { id: string; phaseId: string; status: string; implementationSummary: string; artifactLinks: string[]; notes: string; }
15	export interface Review { id: string; phaseId: string; decision: string; comments: string; impactOnFuturePhases: string; decidedAt: string; }
16	export interface RevisionEvent { id: string; sourcePhaseId: string; affectedPhaseIds: string[]; summary: string; reason: string; approvedBy: string; createdAt: string; }
17	export interface ConversationReference { id: string; scopeType: ScopeType; scopeId: string; system: ConversationSystem; role: ConversationRole; url: string; status: ConversationStatus; authoritative: boolean; notes: string; }
