1	import React, { useState } from "react";
2	import type { DevProject, ProjectStatus, Phase } from "../../worker/types";
3	
4	interface ProjectHeaderProps {
5	  project: DevProject;
6	  phases: Phase[];
7	  onSave: (updates: Partial<DevProject>) => void;
8	  onCancel: () => void;
9	}
10	
11	const STATUS_OPTIONS: ProjectStatus[] = ["Draft", "Active", "Blocked", "Archived"];
12	
13	const statusColors: Record<ProjectStatus, string> = {
14	  Draft: "#6b7280",
15	  Active: "#16a34a",
16	  Blocked: "#dc2626",
17	  Archived: "#9ca3af",
18	};
19	
20	export default function ProjectHeader({ project, phases, onSave, onCancel }: ProjectHeaderProps) {
21	  const [name, setName] = useState(project.name);
22	  const [objective, setObjective] = useState(project.objective);
23	  const [status, setStatus] = useState<ProjectStatus>(project.status);
24	
25	  const activePhase = phases.find((p) => p.id === project.activePhaseId);
26	
27	  const handleSave = () => {
28	    onSave({ name, objective, status });
29	  };
30	
31	  const isDirty =
32	    name !== project.name || objective !== project.objective || status !== project.status;
33	
34	  return (
35	    <div style={{ padding: "16px", borderBottom: "1px solid #e5e7eb" }}>
36	      <div style={{ display: "flex", alignItems: "flex-start", gap: "12px", marginBottom: "12px" }}>
37	        <input
38	          value={name}
39	          onChange={(e) => setName(e.target.value)}
40	          style={{
41	            flex: 1,
42	            fontSize: "20px",
43	            fontWeight: 600,
44	            border: "1px solid #d1d5db",
45	            borderRadius: "6px",
46	            padding: "6px 10px",
47	            outline: "none",
48	          }}
49	          placeholder="Project name"
50	        />
51	        <select
52	          value={status}
53	          onChange={(e) => setStatus(e.target.value as ProjectStatus)}
54	          style={{
55	            border: "1px solid #d1d5db",
56	            borderRadius: "6px",
57	            padding: "6px 10px",
58	            fontSize: "14px",
59	            color: statusColors[status],
60	            fontWeight: 600,
61	            outline: "none",
62	            cursor: "pointer",
63	          }}
64	        >
65	          {STATUS_OPTIONS.map((s) => (
66	            <option key={s} value={s} style={{ color: statusColors[s] }}>
67	              {s}
68	            </option>
69	          ))}
70	        </select>
71	      </div>
72	
73	      <textarea
74	        value={objective}
75	        onChange={(e) => setObjective(e.target.value)}
76	        rows={3}
77	        style={{
78	          width: "100%",
79	          border: "1px solid #d1d5db",
80	          borderRadius: "6px",
81	          padding: "8px 10px",
82	          fontSize: "14px",
83	          resize: "vertical",
84	          outline: "none",
85	          boxSizing: "border-box",
86	        }}
87	        placeholder="Project objective"
88	      />
89	
90	      {activePhase && (
91	        <div
92	          style={{
93	            marginTop: "10px",
94	            fontSize: "13px",
95	            color: "#6b7280",
96	            display: "flex",
97	            alignItems: "center",
98	            gap: "6px",
99	          }}
100	        >
101	          <span style={{ fontWeight: 600, color: "#374151" }}>Active phase:</span>
102	          <span style={{
103	            backgroundColor: "#eff6ff",
104	            color: "#1d4ed8",
105	            padding: "2px 8px",
106	            borderRadius: "12px",
107	            fontWeight: 500,
108	          }}>
109	            Phase {activePhase.phaseNumber}: {activePhase.title}
110	          </span>
111	        </div>
112	      )}
113	
114	      <div style={{ display: "flex", gap: "8px", marginTop: "12px" }}>
115	        <button
116	          onClick={handleSave}
117	          disabled={!isDirty}
118	          style={{
119	            padding: "6px 16px",
120	            backgroundColor: isDirty ? "#2563eb" : "#93c5fd",
121	            color: "#fff",
122	            border: "none",
123	            borderRadius: "6px",
124	            cursor: isDirty ? "pointer" : "not-allowed",
125	            fontSize: "14px",
126	            fontWeight: 500,
127	          }}
128	        >
129	          Save
130	        </button>
131	        <button
132	          onClick={onCancel}
133	          style={{
134	            padding: "6px 16px",
135	            backgroundColor: "#f3f4f6",
136	            color: "#374151",
137	            border: "1px solid #d1d5db",
138	            borderRadius: "6px",
139	            cursor: "pointer",
140	            fontSize: "14px",
141	          }}
142	        >
143	          Cancel
144	        </button>
145	      </div>
146	    </div>
147	  );
148	}
