1	import { DevProject, Phase, Spec, PRD, ConversationReference, ScopeType } from "./types";
2	
3	export class StateStore {
4	  private store: Map<string, any> = new Map();
5	
6	  generateId(): string {
7	    return crypto.randomUUID();
8	  }
9	
10	  createProject(data: Omit<DevProject, "id" | "createdAt" | "updatedAt">): DevProject {
11	    const now = new Date().toISOString();
12	    const project: DevProject = { id: this.generateId(), ...data, createdAt: now, updatedAt: now };
13	    this.store.set(`project:${project.id}`, project);
14	    return project;
15	  }
16	
17	  getProject(id: string): DevProject | null {
18	    return this.store.get(`project:${id}`) ?? null;
19	  }
20	
21	  updateProject(id: string, data: Partial<DevProject>): DevProject {
22	    const existing = this.getProject(id);
23	    if (!existing) throw new Error(`Project ${id} not found`);
24	    const updated: DevProject = { ...existing, ...data, id, updatedAt: new Date().toISOString() };
25	    this.store.set(`project:${id}`, updated);
26	    return updated;
27	  }
28	
29	  deleteProject(id: string): void {
30	    this.store.delete(`project:${id}`);
31	  }
32	
33	  listProjects(): DevProject[] {
34	    const projects: DevProject[] = [];
35	    for (const [key, val] of this.store) {
36	      if (key.startsWith("project:")) projects.push(val);
37	    }
38	    return projects;
39	  }
40	
41	  createPhase(data: Omit<Phase, "id" | "createdAt" | "updatedAt">): Phase {
42	    const now = new Date().toISOString();
43	    const phase: Phase = { id: this.generateId(), ...data, createdAt: now, updatedAt: now };
44	    this.store.set(`phase:${phase.id}`, phase);
45	    return phase;
46	  }
47	
48	  getPhase(id: string): Phase | null {
49	    return this.store.get(`phase:${id}`) ?? null;
50	  }
51	
52	  getPhasesByProject(projectId: string): Phase[] {
53	    const phases: Phase[] = [];
54	    for (const [key, val] of this.store) {
55	      if (key.startsWith("phase:") && val.projectId === projectId) phases.push(val);
56	    }
57	    return phases.sort((a, b) => a.sortOrder - b.sortOrder);
58	  }
59	
60	  updatePhase(id: string, data: Partial<Phase>): Phase {
61	    const existing = this.getPhase(id);
62	    if (!existing) throw new Error(`Phase ${id} not found`);
63	    const updated: Phase = { ...existing, ...data, id, updatedAt: new Date().toISOString() };
64	    this.store.set(`phase:${id}`, updated);
65	    return updated;
66	  }
67	
68	  deletePhase(id: string): void {
69	    this.store.delete(`phase:${id}`);
70	  }
71	
72	  reorderPhases(projectId: string, phaseIds: string[]): void {
73	    phaseIds.forEach((id, index) => {
74	      const phase = this.getPhase(id);
75	      if (phase && phase.projectId === projectId) {
76	        this.store.set(`phase:${id}`, { ...phase, sortOrder: index, updatedAt: new Date().toISOString() });
77	      }
78	    });
79	  }
80	
81	  createSpec(data: Omit<Spec, "id">): Spec {
82	    const spec: Spec = { id: this.generateId(), ...data };
83	    this.store.set(`spec:${spec.id}`, spec);
84	    return spec;
85	  }
86	
87	  getSpecByPhase(phaseId: string): Spec | null {
88	    for (const [key, val] of this.store) {
89	      if (key.startsWith("spec:") && val.phaseId === phaseId) return val;
90	    }
91	    return null;
92	  }
93	
94	  updateSpec(id: string, data: Partial<Spec>): Spec {
95	    const existing = this.store.get(`spec:${id}`);
96	    if (!existing) throw new Error(`Spec ${id} not found`);
97	    const updated: Spec = { ...existing, ...data, id };
98	    this.store.set(`spec:${id}`, updated);
99	    return updated;
100	  }
101	
102	  createPRD(data: Omit<PRD, "id">): PRD {
103	    const prd: PRD = { id: this.generateId(), ...data };
104	    this.store.set(`prd:${prd.id}`, prd);
105	    return prd;
106	  }
107	
108	  getPRDByPhase(phaseId: string): PRD | null {
109	    for (const [key, val] of this.store) {
110	      if (key.startsWith("prd:") && val.phaseId === phaseId) return val;
111	    }
112	    return null;
113	  }
114	
115	  updatePRD(id: string, data: Partial<PRD>): PRD {
116	    const existing = this.store.get(`prd:${id}`);
117	    if (!existing) throw new Error(`PRD ${id} not found`);
118	    const updated: PRD = { ...existing, ...data, id };
119	    this.store.set(`prd:${id}`, updated);
120	    return updated;
121	  }
122	
123	  createConversationRef(data: Omit<ConversationReference, "id">): ConversationReference {
124	    const ref: ConversationReference = { id: this.generateId(), ...data };
125	    this.store.set(`convref:${ref.id}`, ref);
126	    return ref;
127	  }
128	
129	  getConversationRefs(scopeType: ScopeType, scopeId: string): ConversationReference[] {
130	    const refs: ConversationReference[] = [];
131	    for (const [key, val] of this.store) {
132	      if (key.startsWith("convref:") && val.scopeType === scopeType && val.scopeId === scopeId) refs.push(val);
133	    }
134	    return refs;
135	  }
136	
137	  updateConversationRef(id: string, data: Partial<ConversationReference>): ConversationReference {
138	    const existing = this.store.get(`convref:${id}`);
139	    if (!existing) throw new Error(`ConversationReference ${id} not found`);
140	    const updated: ConversationReference = { ...existing, ...data, id };
141	    this.store.set(`convref:${id}`, updated);
142	    return updated;
143	  }
144	
145	  deleteConversationRef(id: string): void {
146	    this.store.delete(`convref:${id}`);
147	  }
148	}
149	
150	export const store = new StateStore();
